  public static abstract class BoolType extends TLObject {
    public static final String TYPE = "Bool";

    public static BoolType readType(TLInputStream istream, TLContext context) throws Exception {
      int id = istream.readInt();
      istream.skip(-4);
      BoolType a = null;
      switch (id) {
        case boolFalse.ID:
          a = new boolFalse();
          break;
        case boolTrue.ID:
          a = new boolTrue();
          break;
        default:
          a = null;

      }
      if (a != null) {
        a.read(istream, context);
      } else {
        throw new TLNotFoundException(id);
      }
      return a;
    }
  }

