    @Override
    public void readParams(TLInputStream istream, TLContext context) throws Exception {
      flags = istream.readInt32();
      if ((flags & 128) != 0) {
        imported = true;
      }
      if ((flags & 2048) != 0) {
        saved_out = true;
      }
      if ((flags & 1) != 0) {
        from_id = PeerType.readType(istream, context);
      }
      if ((flags & 32) != 0) {
        from_name = istream.readTLString();
      }
      date = istream.readInt32();
      if ((flags & 4) != 0) {
        channel_post = istream.readInt32();
      }
      if ((flags & 8) != 0) {
        post_author = istream.readTLString();
      }
      if ((flags & 16) != 0) {
        saved_from_peer = PeerType.readType(istream, context);
      }
      if ((flags & 16) != 0) {
        saved_from_msg_id = istream.readInt32();
      }
      if ((flags & 256) != 0) {
        saved_from_id = PeerType.readType(istream, context);
      }
      if ((flags & 512) != 0) {
        saved_from_name = istream.readTLString();
      }
      if ((flags & 1024) != 0) {
        saved_date = istream.readInt32();
      }
      if ((flags & 64) != 0) {
        psa_type = istream.readTLString();
      }

    }

    @Override
    public void writeParams(TLOutputStream ostream) throws Exception {
      flags = imported ? (flags | 128) : (flags & ~128);
      flags = saved_out ? (flags | 2048) : (flags & ~2048);
      flags = from_id != null ? (flags | 1) : (flags & ~1);
      flags = from_name != null ? (flags | 32) : (flags & ~32);
      flags = channel_post != null ? (flags | 4) : (flags & ~4);
      flags = post_author != null ? (flags | 8) : (flags & ~8);
      flags = saved_from_peer != null ? (flags | 16) : (flags & ~16);
      flags = saved_from_msg_id != null ? (flags | 16) : (flags & ~16);
      flags = saved_from_id != null ? (flags | 256) : (flags & ~256);
      flags = saved_from_name != null ? (flags | 512) : (flags & ~512);
      flags = saved_date != null ? (flags | 1024) : (flags & ~1024);
      flags = psa_type != null ? (flags | 64) : (flags & ~64);
      ostream.writeInt32(flags);
      if ((flags & 128) != 0) {

      }
      if ((flags & 2048) != 0) {

      }
      if ((flags & 1) != 0) {
        from_id.write(ostream);
      }
      if ((flags & 32) != 0) {
        ostream.writeTLString(from_name);
      }
      ostream.writeInt32(date);
      if ((flags & 4) != 0) {
        ostream.writeInt32(channel_post);
      }
      if ((flags & 8) != 0) {
        ostream.writeTLString(post_author);
      }
      if ((flags & 16) != 0) {
        saved_from_peer.write(ostream);
      }
      if ((flags & 16) != 0) {
        ostream.writeInt32(saved_from_msg_id);
      }
      if ((flags & 256) != 0) {
        saved_from_id.write(ostream);
      }
      if ((flags & 512) != 0) {
        ostream.writeTLString(saved_from_name);
      }
      if ((flags & 1024) != 0) {
        ostream.writeInt32(saved_date);
      }
      if ((flags & 64) != 0) {
        ostream.writeTLString(psa_type);
      }

    }

