  public static class channelAdminLogEventActionPinTopic extends ChannelAdminLogEventActionType {
    public static final int ID = 0x5d8d353b;
    public static final boolean IS_CONSTRUCTOR = true;
    public static final String NAME = "channelAdminLogEventActionPinTopic";
    public int flags;
    public ForumTopicType prev_topic = null;
    public ForumTopicType new_topic = null;


    @Override
    public int getId() {
      return ID;
    }

    @Override
    public boolean isConstructor() {
      return IS_CONSTRUCTOR;
    }

    @Override
    public String getName() {
      return NAME;
    }

    @Override
    public void readParams(TLInputStream istream, TLContext context) throws Exception {
      flags = istream.readInt32();
      if ((flags & 1) != 0) {
        prev_topic = ForumTopicType.readType(istream, context);
      }
      if ((flags & 2) != 0) {
        new_topic = ForumTopicType.readType(istream, context);
      }

    }

    @Override
    public void writeParams(TLOutputStream ostream) throws Exception {
      flags = prev_topic != null ? (flags | 1) : (flags & ~1);
      flags = new_topic != null ? (flags | 2) : (flags & ~2);
      ostream.writeInt32(flags);
      if ((flags & 1) != 0) {
        prev_topic.write(ostream);
      }
      if ((flags & 2) != 0) {
        new_topic.write(ostream);
      }

    }

    @Override
    public JsonObject toJSON() {
      Map<String, Object> _json = new LinkedHashMap<>();
      _json.put("@id", getId());
      _json.put("@name", getName());
      _json.put("@type", TYPE);
      _json.put("flags", flags);
      _json.put("prev_topic", prev_topic != null ? prev_topic.toJSON() : null);
      _json.put("new_topic", new_topic != null ? new_topic.toJSON() : null);

      Gson gson = new Gson();
      return gson.toJsonTree(_json).getAsJsonObject();
    }

    @Override
    public String toString() {
      return toJSON().toString();
    }
  }


