    public String getName() {
      return NAME;
    }

    @Override
    public void readParams(TLInputStream istream, TLContext context) throws Exception {
      flags = istream.readInt32();
      if ((flags & 1) != 0) {
        creator = true;
      }
      if ((flags & 2) != 0) {
        default_ = true;
      }
      if ((flags & 32) != 0) {
        for_chat = true;
      }
      id = istream.readInt64();
      access_hash = istream.readInt64();
      slug = istream.readTLString();
      title = istream.readTLString();
      if ((flags & 4) != 0) {
        document = DocumentType.readType(istream, context);
      }
      if ((flags & 8) != 0) {
        settings = new TLVector<>(ThemeSettingsType.class);
        settings.read(istream, context);
      }
      if ((flags & 64) != 0) {
        emoticon = istream.readTLString();
      }
      if ((flags & 16) != 0) {
        installs_count = istream.readInt32();
      }

    }

    @Override
    public void writeParams(TLOutputStream ostream) throws Exception {
      flags = creator ? (flags | 1) : (flags & ~1);
      flags = default_ ? (flags | 2) : (flags & ~2);
      flags = for_chat ? (flags | 32) : (flags & ~32);
      flags = document != null ? (flags | 4) : (flags & ~4);
      flags = settings != null ? (flags | 8) : (flags & ~8);
      flags = emoticon != null ? (flags | 64) : (flags & ~64);
      flags = installs_count != null ? (flags | 16) : (flags & ~16);
      ostream.writeInt32(flags);
      if ((flags & 1) != 0) {

      }
      if ((flags & 2) != 0) {

      }
      if ((flags & 32) != 0) {

      }
      ostream.writeInt64(id);
      ostream.writeInt64(access_hash);
      ostream.writeTLString(slug);
      ostream.writeTLString(title);
      if ((flags & 4) != 0) {
        document.write(ostream);
      }
      if ((flags & 8) != 0) {
        settings.write(ostream);
      }
      if ((flags & 64) != 0) {
        ostream.writeTLString(emoticon);
      }
      if ((flags & 16) != 0) {
        ostream.writeInt32(installs_count);
      }

    }

    @Override
    public JsonObject toJSON() {
      Map<String, Object> _json = new LinkedHashMap<>();
      _json.put("@id", getId());
      _json.put("@name", getName());
      _json.put("@type", TYPE);
      _json.put("flags", flags);
      _json.put("creator", creator);
      _json.put("default", default_);
      _json.put("for_chat", for_chat);
      _json.put("id", id);
      _json.put("access_hash", access_hash);
      _json.put("slug", slug);
      _json.put("title", title);
      _json.put("document", document != null ? document.toJSON() : null);
      _json.put("settings", settings != null ? settings.toJSON() : null);
      _json.put("emoticon", emoticon);
      _json.put("installs_count", installs_count);

      Gson gson = new Gson();
      return gson.toJsonTree(_json).getAsJsonObject();
    }

