      if ((flags & 128) != 0) {
        bot_payload = istream.readTLBytes();
      }
      if ((flags & 256) != 0) {
        msg_id = istream.readInt32();
      }
      if ((flags & 512) != 0) {
        extended_media = new TLVector<>(MessageMediaType.class);
        extended_media.read(istream, context);
      }
      if ((flags & 4096) != 0) {
        subscription_period = istream.readInt32();
      }
      if ((flags & 8192) != 0) {
        giveaway_post_id = istream.readInt32();
      }
      if ((flags & 16384) != 0) {
        stargift = StarGiftType.readType(istream, context);
      }
      if ((flags & 32768) != 0) {
        floodskip_number = istream.readInt32();
      }
      if ((flags & 65536) != 0) {
        starref_commission_permille = istream.readInt32();
      }
      if ((flags & 131072) != 0) {
        starref_peer = PeerType.readType(istream, context);
      }
      if ((flags & 131072) != 0) {
        starref_amount = StarsAmountType.readType(istream, context);
      }

