      flags = stargift_upgrade ? (flags | 262144) : (flags & ~262144);
      flags = title != null ? (flags | 1) : (flags & ~1);
      flags = description != null ? (flags | 2) : (flags & ~2);
      flags = photo != null ? (flags | 4) : (flags & ~4);
      flags = transaction_date != null ? (flags | 32) : (flags & ~32);
      flags = transaction_url != null ? (flags | 32) : (flags & ~32);
      flags = bot_payload != null ? (flags | 128) : (flags & ~128);
      flags = msg_id != null ? (flags | 256) : (flags & ~256);
