      flags = subscription_period != null ? (flags | 4096) : (flags & ~4096);
      flags = giveaway_post_id != null ? (flags | 8192) : (flags & ~8192);
      flags = stargift != null ? (flags | 16384) : (flags & ~16384);
      flags = floodskip_number != null ? (flags | 32768) : (flags & ~32768);
      flags = starref_commission_permille != null ? (flags | 65536) : (flags & ~65536);
      flags = starref_peer != null ? (flags | 131072) : (flags & ~131072);
      flags = starref_amount != null ? (flags | 131072) : (flags & ~131072);
      ostream.writeInt32(flags);
