      @Override
      public void readParams(TLInputStream istream, TLContext context) throws Exception {
        flags = istream.readInt32();
        if ((flags & 1) != 0) {
          can_not_skip = true;
        }
        id = istream.readInt32();
        version = istream.readTLString();
        text = istream.readTLString();
        entities.read(istream, context);
        if ((flags & 2) != 0) {
          document = ApiScheme.DocumentType.readType(istream, context);
        }
        if ((flags & 4) != 0) {
          url = istream.readTLString();
        }
        if ((flags & 8) != 0) {
          sticker = ApiScheme.DocumentType.readType(istream, context);
        }

      }

      @Override
      public void writeParams(TLOutputStream ostream) throws Exception {
        flags = can_not_skip ? (flags | 1) : (flags & ~1);
        flags = document != null ? (flags | 2) : (flags & ~2);
        flags = url != null ? (flags | 4) : (flags & ~4);
        flags = sticker != null ? (flags | 8) : (flags & ~8);
        ostream.writeInt32(flags);
        if ((flags & 1) != 0) {

        }
        ostream.writeInt32(id);
        ostream.writeTLString(version);
        ostream.writeTLString(text);
        entities.write(ostream);
        if ((flags & 2) != 0) {
          document.write(ostream);
        }
        if ((flags & 4) != 0) {
          ostream.writeTLString(url);
        }
        if ((flags & 8) != 0) {
          sticker.write(ostream);
        }

      }

