    public static class peerColorOption extends ApiScheme.help.PeerColorOptionType {
      public static final int ID = 0xadec6ebe;
      public static final boolean IS_CONSTRUCTOR = true;
      public static final String NAME = "help.peerColorOption";
      public int flags;
      public boolean hidden;
      public int color_id;
      public ApiScheme.help.PeerColorSetType colors = null;
      public ApiScheme.help.PeerColorSetType dark_colors = null;
      public Integer channel_min_level;
      public Integer group_min_level;


      @Override
      public int getId() {
        return ID;
      }

      @Override
      public boolean isConstructor() {
        return IS_CONSTRUCTOR;
      }

      @Override
      public String getName() {
        return NAME;
      }

      @Override
      public void readParams(TLInputStream istream, TLContext context) throws Exception {
        flags = istream.readInt32();
        if ((flags & 1) != 0) {
          hidden = true;
        }
        color_id = istream.readInt32();
        if ((flags & 2) != 0) {
          colors = ApiScheme.help.PeerColorSetType.readType(istream, context);
        }
        if ((flags & 4) != 0) {
          dark_colors = ApiScheme.help.PeerColorSetType.readType(istream, context);
        }
        if ((flags & 8) != 0) {
          channel_min_level = istream.readInt32();
        }
        if ((flags & 16) != 0) {
          group_min_level = istream.readInt32();
        }

      }

      @Override
      public void writeParams(TLOutputStream ostream) throws Exception {
        flags = hidden ? (flags | 1) : (flags & ~1);
        flags = colors != null ? (flags | 2) : (flags & ~2);
        flags = dark_colors != null ? (flags | 4) : (flags & ~4);
        flags = channel_min_level != null ? (flags | 8) : (flags & ~8);
        flags = group_min_level != null ? (flags | 16) : (flags & ~16);
        ostream.writeInt32(flags);
        if ((flags & 1) != 0) {

        }
        ostream.writeInt32(color_id);
        if ((flags & 2) != 0) {
          colors.write(ostream);
        }
        if ((flags & 4) != 0) {
          dark_colors.write(ostream);
        }
        if ((flags & 8) != 0) {
          ostream.writeInt32(channel_min_level);
        }
        if ((flags & 16) != 0) {
          ostream.writeInt32(group_min_level);
        }

      }

      @Override
      public JsonObject toJSON() {
        Map<String, Object> _json = new LinkedHashMap<>();
        _json.put("@id", getId());
        _json.put("@name", getName());
        _json.put("@type", TYPE);
        _json.put("flags", flags);
        _json.put("hidden", hidden);
        _json.put("color_id", color_id);
        _json.put("colors", colors != null ? colors.toJSON() : null);
        _json.put("dark_colors", dark_colors != null ? dark_colors.toJSON() : null);
        _json.put("channel_min_level", channel_min_level);
        _json.put("group_min_level", group_min_level);

        Gson gson = new Gson();
        return gson.toJsonTree(_json).getAsJsonObject();
      }

      @Override
      public String toString() {
        return toJSON().toString();
      }
    }


